class Solution {
    public int countVowelPermutation(int n) {
        long MOD = (long)1e9 + 7;
        long[] dp = new long[5];
        for (int i = 0; i < 5; i++) {
            dp[i] = 1;
        }
        long[][] transitions = {
            {0, 1, 0, 0, 1}, // 'a'
            {1, 0, 1, 0, 0}, // 'e'
            {0, 0, 0, 1, 1}, // 'i'
            {0, 0, 1, 0, 1}, // 'o'
            {1, 0, 0, 0, 0}  // 'u'
        };
        for (int i = 1; i < n; i++) {
            long[] nextDp = new long[5];
            for (int j = 0; j < 5; j++) {
                for (int k = 0; k < 5; k++) {
                    if (transitions[k][j] == 1) {
                        nextDp[j] += dp[k];
                        nextDp[j] %= MOD;
                    }
                }
            }
            dp = nextDp;
        }
        long sum = 0;
        for (long l : dp) {
            sum += l;
            sum %= MOD;
        }
        return (int)sum;
    }
}
